set -euo pipefail
cd "$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"

if [ ! -d .git ]; then
  echo "❌ Run this from your freddy-fixit repo folder."; exit 1
fi

echo "↻ Syncing with GitHub…"
git fetch origin -q
git reset --hard origin/main -q

decode () {
  # decode "<dest path>" "<b64 tmp file>"
  local dest="$1"; local src="$2"
  mkdir -p "$(dirname "$dest")"
  base64 --decode < "$src" > "$dest"
}

